namespace sv_f002840fc0e84b9bb783f96b5375c27b.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// All interactive components in the same circuit share this instance.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChanged;

    private void NotifyChanged() => OnChanged?.Invoke();
}

@* Interactive island embedded in the static layout — shares the circuit's ThemeService *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" style="color: @ThemeService.AccentColor;" title="Current theme">
    @GetIcon() @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged() => InvokeAsync(StateHasChanged);

    private string GetIcon() => ThemeService.Theme switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.Light => "☀️",
        _ => "💻"
    };

    public void Dispose() => ThemeService.OnChanged -= HandleThemeChanged;
}

@* Quick toggle — can be placed anywhere interactive (nav, page, etc.) *@
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        style="border-color: @ThemeService.AccentColor; color: @ThemeService.AccentColor;">
    @GetIcon() @ThemeService.Theme
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
    }

    private string GetIcon() => ThemeService.Theme switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.Light => "☀️",
        _ => "💻"
    };

    private void HandleThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeService.OnChanged -= HandleThemeChanged;
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px; border-color: @ThemeService.AccentColor;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>
        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                var isActive = ThemeService.Theme == mode;
                <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                        style="@(isActive ? $"background-color:{ThemeService.AccentColor};border-color:{ThemeService.AccentColor};" : "")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <div class="d-flex align-items-center gap-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="e => ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd"" />
            <span class="badge" style="background-color: @ThemeService.AccentColor;">
                @ThemeService.AccentColor
            </span>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeService.OnChanged -= HandleThemeChanged;
}

