                        style="@(isActive ? $"background-color:{ThemeService.AccentColor};border-color:{ThemeService.AccentColor};" : "")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <div class="d-flex align-items-center gap-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="e => ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd"" />
            <span class="badge" style="background-color: @ThemeService.AccentColor;">
                @ThemeService.AccentColor
            </span>
        </div>
    </div>
